#include <iostream>
int clamp(int val, int lo, int hi) {
    if (val < lo) return lo;
    if (val > hi) return hi;
    return val;
}
int main() {
    std::cout << clamp(5, 1, 10) << " " << clamp(-3, 0, 5);
}
